mapper.select:
SELECT
_gid AS gid, st_x(st_centroid(_geometry)) AS anno_x, st_y(st_centroid(_geometry)) AS anno_y, st_astext(_geometry) AS geometry
FROM xeus.${tbl}
WHERE ${col} = #{val}

SELECT tbl.st_mgr_no , tbl.ed_mgr_no , tbl.cable_desc , tbl.conn_stat , tbl._gid , tbl._geometry , tbl.theme_mgr_no , theme.net_gbn_cd , theme.theme_nm AS net_nm , theme.ring_no , theme.cable_typ , theme.line_color , theme.link_gbn_cd , st_asgeojson(tbl._geometry) as geojson , st_x(st_centroid(_geometry)) AS _annox , st_y(st_centroid(_geometry)) AS _annoy
FROM xeus.${tbl} as tbl LEFT JOIN xeus.asset_netwk_theme AS theme ON tbl.theme_mgr_no = theme.mgr_no
AND ${col} in (${val})
AND ST_Intersects(ST_MakeEnvelope(${box}, 5186), _geometry)
AND reqst_dat >= #{startDat}
AND reqst_dat <= #{endDat}
AND theme_mgr_no in (${themeMgrNo})
${sortCol} ${sortTyp}
LIMIT ${limit} OFFSET ${offset}
